	@Test
	void sameTypedLogicalStateReusesOneScopedGroup() {
		JoinRegion region = regionWithNonDenseOccurrenceIds();
		BindingUniverse universe = BindingUniverse.create();
		RequiredOuterInputs noOuterInputs = new RequiredOuterInputs(universe.maskOf(Set.of()));
		RequiredOuterInputs tenantOuterInput = new RequiredOuterInputs(universe.maskOf(Set.of("tenant")));
		JoinRegionMemo firstMemo = new JoinRegionMemo(region);

		JoinRegionGroupKey baseState = new JoinRegionGroupKey(
				firstMemo.subsetOfOccurrences(Set.of(11, 70)),
				firstMemo.predicateStateOfIds(Set.of()), noOuterInputs);
		JoinRegionGroupKey equivalentBaseState = new JoinRegionGroupKey(
				firstMemo.subsetOfOccurrences(Set.of(70, 11)),
				firstMemo.predicateStateOfIds(Set.of()),
				new RequiredOuterInputs(universe.maskOf(Set.of())));
		JoinRegionGroupKey predicateState = new JoinRegionGroupKey(baseState.subset(),
				firstMemo.predicateStateOfIds(Set.of(9)), noOuterInputs);
		JoinRegionGroupKey outerInputState = new JoinRegionGroupKey(baseState.subset(), baseState.appliedPredicates(),
				tenantOuterInput);

		int baseGroupId = firstMemo.ensureGroup(baseState);
		int predicateGroupId = firstMemo.ensureGroup(predicateState);
		int outerInputGroupId = firstMemo.ensureGroup(outerInputState);

		JoinRegionMemo secondMemo = new JoinRegionMemo(region);
		JoinRegionGroupKey secondMemoBaseState = new JoinRegionGroupKey(
				secondMemo.subsetOfOccurrences(Set.of(11, 70)),
				secondMemo.predicateStateOfIds(Set.of()), noOuterInputs);

		assertAll(
				() -> assertEquals(0, baseGroupId, "Scoped group IDs must start densely at zero"),
				() -> assertEquals(baseGroupId, firstMemo.ensureGroup(equivalentBaseState),
						"Equivalent typed state must reuse its scoped group"),
				() -> assertEquals(1, predicateGroupId,
						"Applied predicates are part of scoped logical identity"),
				() -> assertEquals(2, outerInputGroupId,
						"Required outer inputs are part of scoped logical identity"),
				() -> assertNotEquals(baseGroupId, predicateGroupId),
				() -> assertNotEquals(baseGroupId, outerInputGroupId),
				() -> assertEquals(3, firstMemo.groupCount()),
				() -> assertEquals(0, secondMemo.ensureGroup(secondMemoBaseState),
						"A separate join-region memo owns an independent dense group namespace"),
				() -> assertEquals(1, secondMemo.groupCount(),
						"State inserted into one scoped memo must not leak into another"));
	}

	@Test
	void appliedDirectedEdgesArePartOfScopedLogicalIdentity() {
		JoinSubset left = JoinSubset.ofOrdinals(0);
		JoinSubset right = JoinSubset.ofOrdinals(1);
		JoinRegion region = new JoinRegion(List.of(new JoinFactor(11, 101), new JoinFactor(42, 102)), List.of(),
				List.of(), List.of(new JoinEdge(19, JoinEdge.Kind.ANTI, JoinEdge.Origin.NOT_EXISTS, left, right,
						left.union(right), Set.of())));
		JoinRegionMemo memo = new JoinRegionMemo(region);
		JoinSubset full = memo.subsetOfOccurrences(Set.of(11, 42));
		JoinRegionGroupKey unapplied = new JoinRegionGroupKey(full, PredicateState.EMPTY, AppliedEdgeState.EMPTY,
				RequiredOuterInputs.NONE);
		JoinRegionGroupKey applied = new JoinRegionGroupKey(full, PredicateState.EMPTY,
				memo.edgeStateOfIds(Set.of(19)), RequiredOuterInputs.NONE);

		int unappliedGroupId = memo.ensureGroup(unapplied);
		int appliedGroupId = memo.ensureGroup(applied);

		assertAll(
				() -> assertNotEquals(unappliedGroupId, appliedGroupId),
				() -> assertEquals(1, memo.groupKey(appliedGroupId).appliedEdges().size()),
				() -> assertEquals(appliedGroupId, memo.ensureGroup(new JoinRegionGroupKey(full, PredicateState.EMPTY,
						memo.edgeStateOfIds(List.of(19)), RequiredOuterInputs.NONE))),
				() -> assertEquals(2, memo.groupCount()));
	}

	@Test
	void oneScopedGroupRejectsDifferentCandidateBindingShapes() {
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey group = state(memo, 11);
		BindingUniverse universe = BindingUniverse.create();
		BindingMask firstPossible = universe.maskOf(Set.of("shared", "optional"));
		BindingMask firstAssured = universe.maskOf(Set.of("shared"));
		BindingMask incompatiblePossible = universe.maskOf(Set.of("shared"));

		memo.offerCandidate(candidate(group, "first-shape", unitCost(), firstPossible, firstAssured));
		IllegalArgumentException failure = assertThrows(IllegalArgumentException.class,
				() -> memo.offerCandidate(candidate(group, "incompatible-shape", unitCost(), incompatiblePossible,
						incompatiblePossible)));

		assertEquals("candidate binding shape differs from scoped group 0", failure.getMessage());
	}

	@Test
	void bit64AndBit127DoNotAliasLowerFactors() {
		JoinSubset lower = JoinSubset.ofOrdinals(0, 63);
		JoinSubset upper = JoinSubset.ofOrdinals(64, 127);

		assertAll(
				() -> assertEquals(2, lower.size()),
				() -> assertEquals(2, upper.size()),
				() -> assertTrue(lower.contains(0)),
				() -> assertTrue(lower.contains(63)),
				() -> assertFalse(lower.contains(64)),
				() -> assertFalse(lower.contains(127)),
				() -> assertTrue(upper.contains(64)),
				() -> assertTrue(upper.contains(127)),
				() -> assertFalse(upper.contains(0), "Bit 64 must not wrap onto bit 0"),
				() -> assertFalse(upper.contains(63), "Bit 127 must not wrap onto bit 63"),
				() -> assertNotEquals(lower, upper));
	}

	@Test
	void laterCheaperAutoCandidateEvictsRetainedCandidateAfterTruncation() {
		JoinRegionMemo memo = autoMemo(1);
		JoinRegionGroupKey group = state(memo, 11, 42);
		int groupId = memo.ensureGroup(group);
		PhysicalOperatorId operator = PhysicalOperatorId.of("same-join");
		ProvidedPhysicalProperties provided = ProvidedPhysicalProperties.builder().operator(operator).build();

		memo.offerCandidate(candidate(group, operator, provided,
				new ExecutionCost(0.0d, 100.0d, 0.0d, 1.0d, 0.0d, 0.0d), -1, -1));
		memo.offerCandidate(candidate(group, operator, provided,
				new ExecutionCost(0.0d, 90.0d, 0.0d, 2.0d, 0.0d, 0.0d), -1, -1));
		memo.offerCandidate(candidate(group, operator, provided,
				new ExecutionCost(0.0d, 10.0d, 0.0d, 3.0d, 0.0d, 0.0d), -1, -1));

		List<JoinRegionCandidate> retained = memo.frontier(groupId);
		assertAll(
				() -> assertTrue(memo.frontierTruncated(),
						"Dropping a nondominated AUTO state must remain visible as approximation"),
				() -> assertEquals(1, retained.size()),
				() -> assertEquals(10.0d, retained.getFirst().cost().totalWork(),
						"A full frontier must still evaluate and admit a later cheaper candidate"));
	}

