	@Test
	void evictedCandidateIsReclaimedOnlyAfterLastLiveParentDisappears() {
		JoinRegionMemo memo = autoMemo(1);
		JoinRegionGroupKey leftGroup = state(memo, 11);
		JoinRegionGroupKey rightGroup = state(memo, 42);
		JoinRegionGroupKey rootGroup = state(memo, 11, 42);
		PhysicalOperatorId factorOperator = PhysicalOperatorId.of("factor");
		PhysicalOperatorId joinOperator = PhysicalOperatorId.of("join");

		int oldLeftId = memo.offerCandidate(candidate(leftGroup, factorOperator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 100.0d, 0.0d, 0.0d, 0.0d, 0.0d), -1, -1));
		int rightId = memo.offerCandidate(candidate(rightGroup, "right", unitCost()));
		int oldRootId = memo.offerCandidate(joinCandidate(rootGroup, joinOperator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 100.0d, 0.0d, 0.0d, 0.0d, 0.0d), oldLeftId, rightId));

		int newLeftId = memo.offerCandidate(candidate(leftGroup, factorOperator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 10.0d, 0.0d, 0.0d, 0.0d, 0.0d), -1, -1));
		assertEquals(oldLeftId, memo.candidate(oldLeftId).id(),
				"An evicted child must remain live while a retained parent still references it");

		int newRootId = memo.offerCandidate(joinCandidate(rootGroup, joinOperator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 10.0d, 0.0d, 0.0d, 0.0d, 0.0d), newLeftId, rightId));

		assertAll(
				() -> assertThrows(IllegalArgumentException.class, () -> memo.candidate(oldRootId),
						"An evicted root must release its heavyweight candidate payload"),
				() -> assertThrows(IllegalArgumentException.class, () -> memo.candidate(oldLeftId),
						"The old child must be reclaimed when its final live parent disappears"),
				() -> assertEquals(rightId, memo.candidate(rightId).id()),
				() -> assertEquals(newLeftId, memo.candidate(newLeftId).id()),
				() -> assertEquals(newRootId, memo.candidate(newRootId).id()),
				() -> assertEquals(5, memo.candidateCount(),
						"Candidate IDs must remain monotonic even when old payload slots are reclaimed"));
	}

	@Test
	void dominatedEvaluationsDoNotReceiveCandidateIdsOrRemainStored() {
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey firstGroup = state(memo, 11, 42);
		JoinRegionGroupKey secondGroup = state(memo, 70);
		PhysicalOperatorId retainedOperator = PhysicalOperatorId.of("same-implementation");
		ProvidedPhysicalProperties retainedProperties = ProvidedPhysicalProperties.builder()
				.operator(retainedOperator)
				.build();

		assertEquals(0,
				memo.offerCandidate(candidate(firstGroup, retainedOperator, retainedProperties, unitCost(), -1, -1)));
		for (int index = 0; index < 100; index++) {
			int rejectedId = memo.offerCandidate(candidate(firstGroup, retainedOperator, retainedProperties,
					new ExecutionCost(0.0d, 10.0d + index, 0.0d, 10.0d, 10.0d, 10.0d), -1, -1));
			assertEquals(-1, rejectedId,
					"A rejected evaluation must not expose a candidate ID that can be used as a child");
		}

		assertEquals(1, memo.offerCandidate(candidate(secondGroup, "second-retained", unitCost())),
				"Dense IDs and retained storage count accepted candidate states, not evaluated combinations");
	}

	@Test
	void operatorSpecificCandidatesDoNotDominateOneAnother() {
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey group = state(memo, 11, 42);
		int groupId = memo.ensureGroup(group);

		memo.offerCandidate(candidate(group, "cheap-hash",
				new ExecutionCost(0.0d, 1.0d, 0.0d, 1.0d, 0.0d, 0.0d)));
		memo.offerCandidate(candidate(group, "required-bound-lookup",
				new ExecutionCost(0.0d, 100.0d, 0.0d, 100.0d, 0.0d, 0.0d)));

		Set<PhysicalOperatorId> retainedOperators = memo.frontier(groupId)
				.stream()
				.map(JoinRegionCandidate::operator)
				.collect(java.util.stream.Collectors.toUnmodifiableSet());
		assertEquals(Set.of(PhysicalOperatorId.of("cheap-hash"), PhysicalOperatorId.of("required-bound-lookup")),
				retainedOperators,
				"A different physical operator remains necessary for an operator-specific required property");
	}

	@Test
	void exactFrontierRetainsNondominatedResourceTradeoffs() {
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey group = state(memo, 11, 42);
		int groupId = memo.ensureGroup(group);
		PhysicalOperatorId operator = PhysicalOperatorId.of("same-join");

		memo.offerCandidate(candidate(group, operator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 10.0d, 0.0d, 100.0d, 0.0d, 0.0d), -1, -1));
		memo.offerCandidate(candidate(group, operator, ProvidedPhysicalProperties.ANY,
				new ExecutionCost(0.0d, 100.0d, 0.0d, 10.0d, 0.0d, 0.0d), -1, -1));

		Set<ExecutionCost> retainedCosts = memo.frontier(groupId)
				.stream()
				.map(JoinRegionCandidate::cost)
				.collect(java.util.stream.Collectors.toUnmodifiableSet());
		assertEquals(Set.of(new ExecutionCost(0.0d, 10.0d, 0.0d, 100.0d, 0.0d, 0.0d),
				new ExecutionCost(0.0d, 100.0d, 0.0d, 10.0d, 0.0d, 0.0d)), retainedCosts,
				"EXACT must retain every component-wise nondominated executable-resource tradeoff");
	}

	@Test
	void parameterizedCandidateCannotDominateLessParameterizedCandidate() {
		BindingUniverse universe = BindingUniverse.create();
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey group = state(memo, 11, 42);
		int groupId = memo.ensureGroup(group);
		PhysicalOperatorId operator = PhysicalOperatorId.of("same-join");
		ProvidedPhysicalProperties independent = ProvidedPhysicalProperties.ANY;
		ProvidedPhysicalProperties parameterized = ProvidedPhysicalProperties.builder()
				.parameterBindings(universe.maskOf(Set.of("outer")))
				.build();

		memo.offerCandidate(candidate(group, operator, independent,
				new ExecutionCost(0.0d, 100.0d, 0.0d, 100.0d, 100.0d, 100.0d), -1, -1));
		memo.offerCandidate(candidate(group, operator, parameterized,
				new ExecutionCost(0.0d, 1.0d, 0.0d, 1.0d, 1.0d, 1.0d), -1, -1));

		Set<BindingMask> retainedParameters = memo.frontier(groupId)
				.stream()
				.map(candidate -> candidate.provided().parameterBindings())
				.collect(java.util.stream.Collectors.toUnmodifiableSet());
		assertEquals(Set.of(BindingMask.EMPTY, universe.maskOf(Set.of("outer"))), retainedParameters,
				"A cheaper plan requiring more outer bindings cannot dominate an independently executable plan");
	}

	@Test
	void rootReachableRecipesExcludeUnselectedSearchStates() {
		JoinRegionMemo memo = exactMemo();
		JoinRegionGroupKey leftGroup = state(memo, 11);
		JoinRegionGroupKey rightGroup = state(memo, 42);
		JoinRegionGroupKey rootGroup = state(memo, 11, 42);
		JoinRegionGroupKey unselectedGroup = state(memo, 70);
		memo.ensureGroup(leftGroup);
		memo.ensureGroup(rightGroup);
		memo.ensureGroup(rootGroup);
		memo.ensureGroup(unselectedGroup);

		int leftId = memo.offerCandidate(candidate(leftGroup, "left-factor", unitCost()));
		int rightId = memo.offerCandidate(candidate(rightGroup, "right-factor", unitCost()));
		int unselectedId = memo.offerCandidate(candidate(unselectedGroup, "unselected-factor", unitCost()));
		int rootId = memo.offerCandidate(candidate(rootGroup, PhysicalOperatorId.of("selected-root"),
				ProvidedPhysicalProperties.ANY, unitCost(), leftId, rightId));

		Set<JoinRegionRecipe> reachable = Set.copyOf(memo.reachableRecipes(List.of(rootId)));
		assertAll(
				() -> assertTrue(unselectedId >= 0, "The excluded recipe must be a real retained search state"),
				() -> assertEquals(Set.of(
						JoinRegionRecipe.named("left-factor"),
						JoinRegionRecipe.named("right-factor"),
						JoinRegionRecipe.named("selected-root")), reachable),
				() -> assertFalse(reachable.contains(JoinRegionRecipe.named("unselected-factor")),
						"Global export must trace only the selected root's reachable derivation DAG"));
	}

	private static JoinRegionMemo autoMemo(int frontierLimit) {
		return new JoinRegionMemo(regionWithNonDenseOccurrenceIds(),
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT),
				JoinRegionMemo.Retention.auto(frontierLimit, 100));
	}

	private static JoinRegionMemo exactMemo() {
		return new JoinRegionMemo(regionWithNonDenseOccurrenceIds(),
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT),
				JoinRegionMemo.Retention.exact(100));
	}

	private static JoinRegionGroupKey state(JoinRegionMemo memo, Integer... occurrenceIds) {
		return new JoinRegionGroupKey(memo.subsetOfOccurrences(List.of(occurrenceIds)), PredicateState.EMPTY,
				RequiredOuterInputs.NONE);
	}

	private static JoinRegionCandidate candidate(JoinRegionGroupKey group, String operator, ExecutionCost cost) {
		PhysicalOperatorId operatorId = PhysicalOperatorId.of(operator);
		return candidate(group, operatorId,
				ProvidedPhysicalProperties.builder().operator(operatorId).build(), cost, -1, -1);
	}

	private static JoinRegionCandidate candidate(JoinRegionGroupKey group, PhysicalOperatorId operator,
			ProvidedPhysicalProperties provided, ExecutionCost cost, int leftCandidateId, int rightCandidateId) {
		return new JoinRegionCandidate(-1, group, BindingMask.EMPTY, BindingMask.EMPTY, provided, operator, cost,
				CardinalityEstimate.exact(1.0d, "join-region-memo-test"), EstimateRisk.NONE, leftCandidateId,
				rightCandidateId,
				JoinRegionRecipe.named(operator.value()));
	}

	private static JoinRegionCandidate candidate(JoinRegionGroupKey group, String operator, ExecutionCost cost,
			BindingMask possibleBindings, BindingMask assuredBindings) {
		PhysicalOperatorId operatorId = PhysicalOperatorId.of(operator);
		return new JoinRegionCandidate(-1, group, possibleBindings, assuredBindings,
				ProvidedPhysicalProperties.builder().operator(operatorId).build(), operatorId, cost,
				CardinalityEstimate.exact(1.0d, "join-region-memo-test"), EstimateRisk.NONE, -1, -1,
				JoinRegionRecipe.named(operator));
	}

	private static JoinRegionCandidate joinCandidate(JoinRegionGroupKey group, PhysicalOperatorId operator,
			ProvidedPhysicalProperties provided, ExecutionCost cost, int leftCandidateId, int rightCandidateId) {
		return new JoinRegionCandidate(-1, group, BindingMask.EMPTY, BindingMask.EMPTY, provided, operator, cost,
				CardinalityEstimate.exact(1.0d, "join-region-memo-test"), EstimateRisk.NONE, leftCandidateId,
				rightCandidateId, JoinRegionRecipe.join("test"));
	}

	private static ExecutionCost unitCost() {
		return new ExecutionCost(0.0d, 1.0d, 0.0d, 0.0d, 0.0d, 0.0d);
	}

	private static JoinRegion regionWithNonDenseOccurrenceIds() {
		return new JoinRegion(
				List.of(new JoinFactor(11, 101), new JoinFactor(42, 102), new JoinFactor(70, 103)),
				List.of(),
				List.of(new JoinPredicate(9, new Bound(new Var("tenant")), Set.of("tenant"), List.of())));
	}
